-- Seed: ejercicios_biblioteca
-- Grupos: Pecho, Gemelos, Cuádriceps, Isquiotibiales, Bíceps, Tríceps
-- Contexto: app fitness en casa para mujeres en Argentina (descripciones en "vos")

INSERT INTO ejercicios_biblioteca (nombre, descripcion, video, grupo_muscular, equipamiento_requerido, tipo, patron_movimiento, nivel_dificultad) VALUES

-- ============ PECHO ============
('Flexiones de rodillas — Claude', 'Apoyá las rodillas en el piso y mantené el cuerpo recto desde la cabeza hasta las rodillas. Bajá el pecho controlando, sin dejar caer la cadera.', NULL, 'Pecho', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 1),
('Press de pecho en suelo con mancuernas — Claude', 'Acostada boca arriba con las rodillas flexionadas, empujá las mancuernas hacia arriba sin trabar los codos. Bajá hasta que los codos toquen apenas el piso.', NULL, 'Pecho', 'mancuernas', 'fuerza', 'empuje_horizontal', 1),
('Aperturas de pecho en suelo — Claude', 'Tumbada en el piso con mancuernas livianas, abrí los brazos en arco con codos apenas flexionados. Sentí el estiramiento del pecho y volvé sin chocar las pesas.', NULL, 'Pecho', 'mancuernas', 'fuerza', 'empuje_horizontal', 1),
('Press de pecho con banda elástica — Claude', 'Pasá la banda por la espalda y empujá las manos hacia adelante hasta estirar los brazos. Controlá la vuelta para no perder la tensión.', NULL, 'Pecho', 'banda_elastica', 'fuerza', 'empuje_horizontal', 1),
('Flexiones en pared — Claude', 'Apoyá las manos en la pared a la altura del pecho y acercá el cuerpo flexionando los codos. Mantené el abdomen firme durante todo el recorrido.', NULL, 'Pecho', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 1),
('Flexiones tradicionales — Claude', 'Manos a la altura del pecho, cuerpo recto como tabla. Bajá llevando los codos a unos 45 grados y empujá fuerte sin arquear la espalda.', NULL, 'Pecho', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 2),
('Press inclinado con mancuernas — Claude', 'En un banco inclinado, empujá las mancuernas hacia arriba juntando un poco arriba. Trabajás más la parte alta del pecho, no abras tanto los codos.', NULL, 'Pecho', 'mancuernas', 'fuerza', 'empuje_vertical', 2),
('Aperturas con mancuernas en banco — Claude', 'Acostada en un banco, abrí los brazos en arco amplio con codos semiflexionados. Imaginá que abrazás un árbol grande al volver.', NULL, 'Pecho', 'mancuernas', 'fuerza', 'empuje_horizontal', 2),
('Flexiones con manos juntas (diamante) — Claude', 'Formá un diamante con los dedos debajo del pecho y bajá controlando. Es más exigente, mantené los codos cerca del cuerpo.', NULL, 'Pecho', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 2),
('Press de pecho en máquina — Claude', 'Ajustá el asiento para que las manijas queden a la altura del pecho. Empujá sin trabar codos y volvé despacio sintiendo el músculo.', NULL, 'Pecho', 'maquina', 'fuerza', 'empuje_horizontal', 2),
('Cruce de poleas — Claude', 'Parada en el centro, llevá las manos al frente y abajo juntándolas adelante. Contraé el pecho un segundo antes de soltar la tensión.', NULL, 'Pecho', 'polea', 'fuerza', 'empuje_horizontal', 2),
('Press de banca con barra — Claude', 'Acostada, bajá la barra al pecho con los codos a 45 grados y empujá manteniendo los pies firmes en el piso. No rebotes en el pecho.', NULL, 'Pecho', 'barra', 'fuerza', 'empuje_horizontal', 2),
('Flexiones con pies elevados — Claude', 'Apoyá los pies en un step o silla y bajá el pecho. Al estar inclinada hacia abajo trabajás más la parte alta, mantené el core firme.', NULL, 'Pecho', 'step', 'fuerza', 'empuje_vertical', 3),
('Flexiones explosivas — Claude', 'Bajá controlando y empujá con fuerza para que las manos se despeguen del piso. Caé suave flexionando los codos para amortiguar.', NULL, 'Pecho', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 3),
('Flexiones arqueras — Claude', 'Bajá hacia un brazo estirando el otro hacia el costado. Alterná lados, es casi una flexión a una mano, mantené la cadera estable.', NULL, 'Pecho', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 3),
('Press declinado con mancuernas — Claude', 'Con el banco en declive y la cabeza más abajo, empujá las mancuernas hacia arriba. Enfocás la parte baja del pecho, controlá bien la bajada.', NULL, 'Pecho', 'mancuernas', 'fuerza', 'empuje_horizontal', 3),
('Flexiones con palmada — Claude', 'Empujá explosivo, dale una palmada en el aire y volvé a apoyar amortiguando. Necesitás base de fuerza, hacelo solo si dominás las explosivas.', NULL, 'Pecho', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 3),

-- ============ GEMELOS ============
('Elevación de talones de pie bilateral — Claude', 'Parada con los pies al ancho de cadera, subí lo más alto posible sobre la punta de los pies. Pausá arriba un segundo y bajá despacio.', NULL, 'Gemelos', 'sin_equipamiento', 'fuerza', 'aislamiento', 1),
('Elevación de talones sentada — Claude', 'Sentada con los pies apoyados, levantá los talones empujando con la punta. Si querés más carga apoyá una mancuerna sobre los muslos.', NULL, 'Gemelos', 'sin_equipamiento', 'fuerza', 'aislamiento', 1),
('Saltos suaves en punta de pie — Claude', 'Saltá bajito rebotando solo con los tobillos, sin flexionar mucho las rodillas. Aterrizá suave manteniendo el ritmo constante.', NULL, 'Gemelos', 'sin_equipamiento', 'cardio', 'aislamiento', 1),
('Elevación de talones con banda elástica — Claude', 'Pisá la banda con las puntas de los pies y sostené los extremos. Subí los talones contra la resistencia y bajá controlando.', NULL, 'Gemelos', 'banda_elastica', 'fuerza', 'aislamiento', 1),
('Caminata en punta de pie — Claude', 'Caminá unos pasos manteniéndote en puntas de pie sin apoyar el talón. Mantené el equilibrio y el abdomen activo.', NULL, 'Gemelos', 'sin_equipamiento', 'fuerza', 'aislamiento', 1),
('Elevación de talones unilateral — Claude', 'Parada en una pierna, sostené un apoyo para equilibrio y subí sobre la punta. Bajá lento y completá las repes antes de cambiar de pie.', NULL, 'Gemelos', 'sin_equipamiento', 'fuerza', 'aislamiento', 2),
('Elevación de talones con mancuerna — Claude', 'Sostené una mancuerna en una mano y subí sobre las puntas de ambos pies. Buscá el rango completo, bien arriba y bien abajo.', NULL, 'Gemelos', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Calf raise en escalón bilateral — Claude', 'Apoyá las puntas en el borde de un step dejando caer los talones por debajo. Subí hasta lo más alto y sentí el estiramiento abajo.', NULL, 'Gemelos', 'step', 'fuerza', 'aislamiento', 2),
('Elevación de talones con kettlebell — Claude', 'Sostené una kettlebell con ambas manos delante del cuerpo y elevá los talones. Mantené el torso erguido y subí parejo.', NULL, 'Gemelos', 'kettlebell', 'fuerza', 'aislamiento', 2),
('Elevación de talones en máquina — Claude', 'Acomodá los hombros bajo las almohadillas y subí sobre las puntas. Hacé pausa arriba y controlá la bajada para sentir el estiramiento.', NULL, 'Gemelos', 'maquina', 'fuerza', 'aislamiento', 2),
('Elevación de talones sentada con mancuerna — Claude', 'Sentada, apoyá una mancuerna sobre los muslos cerca de las rodillas y elevá los talones. Trabajás más el sóleo, hacelo lento.', NULL, 'Gemelos', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Elevación de talones con barra — Claude', 'Con la barra apoyada en la espalda alta y las puntas en un disco o step, elevá los talones. Mantené el equilibrio con el core firme.', NULL, 'Gemelos', 'barra', 'fuerza', 'aislamiento', 2),
('Calf raise en escalón unilateral — Claude', 'Una sola pierna sobre el borde del step, bajá el talón bien profundo y subí a tope. Apoyate suave de una mano para no perder equilibrio.', NULL, 'Gemelos', 'step', 'fuerza', 'aislamiento', 3),
('Calf raise unilateral con mancuerna — Claude', 'Sobre el borde de un step con una pierna, sostené una mancuerna del mismo lado y elevá el talón. Rango completo y control total.', NULL, 'Gemelos', 'mancuernas', 'fuerza', 'aislamiento', 3),
('Calf raise en prensa — Claude', 'En la prensa de piernas apoyá solo las puntas en el borde de la plataforma. Empujá con los gemelos estirando los tobillos sin trabar rodillas.', NULL, 'Gemelos', 'maquina', 'fuerza', 'aislamiento', 3),
('Saltos a la comba (skipping) — Claude', 'Saltá a la soga rebotando solo con los tobillos y manteniendo las rodillas casi rectas. Ritmo continuo para fatigar bien los gemelos.', NULL, 'Gemelos', 'sin_equipamiento', 'cardio', 'aislamiento', 3),

-- ============ CUÁDRICEPS ============
('Sentadilla al cajón — Claude', 'Bajá hasta sentarte apenas en una silla o cajón y subí sin tomar impulso. Controla el descenso, no te dejes caer de golpe.', NULL, 'Cuádriceps', 'sin_equipamiento', 'fuerza', 'sentadilla', 1),
('Extensión de cuádriceps sentada — Claude', 'Sentada en la máquina, estirá las piernas hasta casi extender y bajá controlando. Apretá el cuádriceps arriba un segundo.', NULL, 'Cuádriceps', 'maquina', 'fuerza', 'aislamiento', 1),
('Wall sit (silla isométrica) — Claude', 'Apoyá la espalda en la pared con las rodillas a 90 grados, como sentada en una silla invisible. Aguantá manteniendo la respiración.', NULL, 'Cuádriceps', 'sin_equipamiento', 'fuerza', 'sentadilla', 1),
('Sentadilla sumo peso corporal — Claude', 'Pies bien abiertos y puntas hacia afuera, bajá llevando la cadera atrás con la espalda recta. Empujá desde los talones para subir.', NULL, 'Cuádriceps', 'sin_equipamiento', 'fuerza', 'sentadilla', 1),
('Sentadilla peso corporal — Claude', 'Pies al ancho de hombros, bajá llevando la cola hacia atrás como si te sentaras. Mantené las rodillas en línea con los pies.', NULL, 'Cuádriceps', 'sin_equipamiento', 'fuerza', 'sentadilla', 1),
('Prensa de piernas — Claude', 'Apoyá los pies en la plataforma al ancho de cadera y empujá sin trabar las rodillas. Bajá hasta 90 grados controlando el peso.', NULL, 'Cuádriceps', 'maquina', 'fuerza', 'sentadilla', 2),
('Step-up con mancuerna — Claude', 'Subí a un step con una pierna sosteniendo mancuernas, sin impulsarte con la pierna de abajo. Bajá controlando y alterná.', NULL, 'Cuádriceps', 'mancuernas', 'fuerza', 'sentadilla', 2),
('Zancada con mancuernas — Claude', 'Dá un paso largo al frente y bajá la rodilla de atrás casi al piso. Empujá con el talón delantero para volver, espalda recta.', NULL, 'Cuádriceps', 'mancuernas', 'fuerza', 'sentadilla', 2),
('Sentadilla goblet — Claude', 'Sostené una mancuerna o kettlebell pegada al pecho y bajá profundo manteniendo el torso erguido. Los codos pasan entre las rodillas.', NULL, 'Cuádriceps', 'mancuernas', 'fuerza', 'sentadilla', 2),
('Sentadilla goblet con kettlebell — Claude', 'Agarrá la kettlebell por los cuernos contra el pecho y bajá hasta el paralelo. Mantené el pecho arriba y empujá desde los talones.', NULL, 'Cuádriceps', 'kettlebell', 'fuerza', 'sentadilla', 2),
('Zancadas caminando — Claude', 'Avanzá dando pasos largos alternando piernas, bajando la rodilla trasera cerca del piso. Mantené el tronco firme y el paso estable.', NULL, 'Cuádriceps', 'mancuernas', 'fuerza', 'sentadilla', 2),
('Sentadilla con barra — Claude', 'Con la barra en la espalda alta, bajá llevando la cadera atrás hasta el paralelo. Mantené la espalda neutra y empujá con todo el pie.', NULL, 'Cuádriceps', 'barra', 'fuerza', 'sentadilla', 2),
('Pistol squat asistido — Claude', 'Bajá en una sola pierna sosteniéndote de un TRX o marco para asistirte. Estirá la otra pierna al frente y subí controlando.', NULL, 'Cuádriceps', 'trx', 'fuerza', 'sentadilla', 3),
('Sentadilla búlgara con peso — Claude', 'Pie de atrás apoyado en un banco, bajá flexionando la pierna delantera con mancuernas en las manos. Mantené el peso en la pierna de adelante.', NULL, 'Cuádriceps', 'mancuernas', 'fuerza', 'sentadilla', 3),
('Prensa unilateral — Claude', 'Empujá la plataforma con una sola pierna controlando el descenso. Más exigente para equilibrar la fuerza entre ambos lados.', NULL, 'Cuádriceps', 'maquina', 'fuerza', 'sentadilla', 3),
('Jump squat (sentadilla con salto) — Claude', 'Bajá a la sentadilla y explotá hacia arriba en un salto. Aterrizá suave flexionando rodillas y volvé a bajar de inmediato.', NULL, 'Cuádriceps', 'sin_equipamiento', 'fuerza', 'sentadilla', 3),

-- ============ ISQUIOTIBIALES ============
('Puente de glúteos con pausa — Claude', 'Acostada con rodillas flexionadas, subí la cadera apretando glúteos y aguantá arriba dos segundos. Bajá despacio sin tocar del todo el piso.', NULL, 'Isquiotibiales', 'sin_equipamiento', 'fuerza', 'bisagra', 1),
('Buenos días peso corporal — Claude', 'Parada con manos en la nuca, llevá la cadera hacia atrás bajando el torso con la espalda recta. Sentí el estiramiento atrás del muslo.', NULL, 'Isquiotibiales', 'sin_equipamiento', 'fuerza', 'bisagra', 1),
('Curl femoral con banda tumbada — Claude', 'Boca abajo con la banda en los tobillos anclada adelante, llevá el talón hacia la cola. Bajá controlando la resistencia.', NULL, 'Isquiotibiales', 'banda_elastica', 'fuerza', 'bisagra', 1),
('Puente de glúteos a una pierna — Claude', 'Con una pierna estirada, subí la cadera empujando solo con el talón apoyado. Mantené la pelvis pareja, sin que caiga un lado.', NULL, 'Isquiotibiales', 'sin_equipamiento', 'fuerza', 'bisagra', 1),
('Peso muerto rumano con mancuernas — Claude', 'Con las mancuernas adelante, llevá la cadera atrás bajando hasta media canilla con la espalda recta. Subí apretando glúteos e isquios.', NULL, 'Isquiotibiales', 'mancuernas', 'fuerza', 'bisagra', 2),
('Puente unilateral con apoyo elevado — Claude', 'Un pie sobre un step y el otro en el aire, subí la cadera empujando con el talón del step. Controlá el descenso sin apoyar la cola.', NULL, 'Isquiotibiales', 'step', 'fuerza', 'bisagra', 2),
('Curl femoral en máquina — Claude', 'Boca abajo en la máquina, llevá los talones hacia la cola apretando los isquios. Bajá despacio sin soltar de golpe.', NULL, 'Isquiotibiales', 'maquina', 'fuerza', 'bisagra', 2),
('Peso muerto rumano con kettlebell — Claude', 'Sostené la kettlebell con ambas manos y llevá la cadera atrás bajándola pegada a las piernas. Espalda neutra durante todo el movimiento.', NULL, 'Isquiotibiales', 'kettlebell', 'fuerza', 'bisagra', 2),
('Peso muerto a una pierna con mancuerna — Claude', 'Parada en una pierna, inclinate hacia adelante bajando la mancuerna mientras la otra pierna sube atrás. Mantené la cadera cerrada.', NULL, 'Isquiotibiales', 'mancuernas', 'fuerza', 'bisagra', 2),
('Curl femoral deslizante en suelo — Claude', 'Acostada con los talones sobre toallas o discos deslizantes, subí la cadera y estirá las piernas deslizando. Volvé flexionando con control.', NULL, 'Isquiotibiales', 'sin_equipamiento', 'fuerza', 'bisagra', 2),
('Puente femoral con TRX — Claude', 'Talones en las cintas del TRX, elevá la cadera y llevá los talones hacia la cola. Mantené el cuerpo recto y el core firme.', NULL, 'Isquiotibiales', 'trx', 'fuerza', 'bisagra', 2),
('Buenos días con barra — Claude', 'Con la barra en la espalda alta, llevá la cadera atrás bajando el torso con la espalda recta. Subí apretando glúteos, no redondees la espalda.', NULL, 'Isquiotibiales', 'barra', 'fuerza', 'bisagra', 3),
('Nordic curl — Claude', 'Arrodillada con los tobillos sujetos, bajá el torso adelante resistiendo con los isquios lo más que puedas. Frená la caída con las manos.', NULL, 'Isquiotibiales', 'sin_equipamiento', 'fuerza', 'bisagra', 3),
('Peso muerto rumano con barra — Claude', 'Con la barra pegada a las piernas, llevá la cadera atrás bajando hasta media canilla. Espalda recta y subí extendiendo la cadera.', NULL, 'Isquiotibiales', 'barra', 'fuerza', 'bisagra', 3),
('Peso muerto rumano unilateral con barra — Claude', 'En una pierna, bajá la barra mientras la pierna libre se eleva atrás. Exige equilibrio y control, mantené la cadera nivelada.', NULL, 'Isquiotibiales', 'barra', 'fuerza', 'bisagra', 3),

-- ============ BÍCEPS ============
('Curl con banda elástica — Claude', 'Pisá la banda y flexioná los codos llevando las manos a los hombros. Mantené los codos pegados al cuerpo y controlá la bajada.', NULL, 'Bíceps', 'banda_elastica', 'fuerza', 'aislamiento', 1),
('Curl martillo liviano — Claude', 'Con las mancuernas en agarre neutro (palmas enfrentadas), subí flexionando sin mover los codos. Bajá despacio sin balancear el cuerpo.', NULL, 'Bíceps', 'mancuernas', 'fuerza', 'aislamiento', 1),
('Curl sentada con mancuernas — Claude', 'Sentada en un banco, flexioná los codos subiendo las mancuernas sin usar impulso. Al sentarte evitás hacer trampa con la espalda.', NULL, 'Bíceps', 'mancuernas', 'fuerza', 'aislamiento', 1),
('Curl con banda sentada — Claude', 'Sentada pisando la banda, flexioná los codos contra la resistencia. La tensión aumenta arriba, apretá el bíceps en el tope.', NULL, 'Bíceps', 'banda_elastica', 'fuerza', 'aislamiento', 1),
('Curl alterno de pie — Claude', 'Subí una mancuerna por vez alternando los brazos, sin mover los codos del costado. Controlá la bajada de cada repetición.', NULL, 'Bíceps', 'mancuernas', 'fuerza', 'aislamiento', 1),
('Curl de concentración — Claude', 'Sentada, apoyá el codo en la parte interna del muslo y subí la mancuerna concentrando el bíceps. Bajá lento sin soltar la tensión.', NULL, 'Bíceps', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Curl 21s — Claude', 'Hacé 7 repes en la mitad de abajo, 7 en la mitad de arriba y 7 completas sin descanso. Sentí el ardor, no aflojes la técnica.', NULL, 'Bíceps', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Curl en banco inclinado — Claude', 'Recostada en un banco inclinado con los brazos colgando, flexioná sin mover los hombros. El estiramiento inicial trabaja más el bíceps.', NULL, 'Bíceps', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Curl martillo con kettlebell — Claude', 'Agarre neutro con la kettlebell, flexioná el codo manteniéndolo fijo al costado. Controlá el peso para que no te tire el hombro.', NULL, 'Bíceps', 'kettlebell', 'fuerza', 'aislamiento', 2),
('Curl en máquina — Claude', 'Apoyá los brazos en la almohadilla y flexioná llevando las manijas hacia vos. Hacé el recorrido completo sin trabar los codos.', NULL, 'Bíceps', 'maquina', 'fuerza', 'aislamiento', 2),
('Curl predicador con banda — Claude', 'Apoyá los brazos sobre un banco inclinado y flexioná contra la banda anclada abajo. Mantené los codos fijos sobre el apoyo.', NULL, 'Bíceps', 'banda_elastica', 'fuerza', 'aislamiento', 2),
('Curl con barra — Claude', 'De pie con la barra en agarre supino al ancho de hombros, flexioná sin balancear la espalda. Bajá controlando hasta extender los brazos.', NULL, 'Bíceps', 'barra', 'fuerza', 'aislamiento', 2),
('Chin-up (dominada supina) — Claude', 'Agarre supino al ancho de hombros, traccioná hasta pasar el mentón sobre la barra. Bajá controlando hasta estirar bien los brazos.', NULL, 'Bíceps', 'sin_equipamiento', 'fuerza', 'jale_vertical', 3),
('Curl con polea baja — Claude', 'De pie frente a la polea baja, flexioná los codos manteniéndolos fijos al costado. La tensión es constante, controlá toda la bajada.', NULL, 'Bíceps', 'polea', 'fuerza', 'aislamiento', 3),
('Curl araña con mancuernas — Claude', 'Apoyada de pecho en un banco inclinado, dejá colgar los brazos y flexioná. Sin impulso, máxima contracción del bíceps en el tope.', NULL, 'Bíceps', 'mancuernas', 'fuerza', 'aislamiento', 3),

-- ============ TRÍCEPS ============
('Extensión de tríceps en suelo peso corporal — Claude', 'En posición de flexión con manos juntas, bajá doblando solo los codos hacia atrás y empujá. Mantené el cuerpo recto como tabla.', NULL, 'Tríceps', 'sin_equipamiento', 'fuerza', 'aislamiento', 1),
('Press cerrado con banda elástica — Claude', 'Pasá la banda por la espalda y empujá las manos al frente con los codos pegados al cuerpo. Estirá completo y volvé controlando.', NULL, 'Tríceps', 'banda_elastica', 'fuerza', 'empuje_horizontal', 1),
('Kickback sentada liviana — Claude', 'Sentada inclinada al frente, llevá la mancuerna hacia atrás extendiendo el codo. Mantené el brazo pegado al torso, solo mové el antebrazo.', NULL, 'Tríceps', 'mancuernas', 'fuerza', 'aislamiento', 1),
('Extensión de tríceps con banda sobre cabeza — Claude', 'Sostené la banda detrás de la cabeza y estirá los brazos hacia arriba. Mantené los codos apuntando adelante y controlá la vuelta.', NULL, 'Tríceps', 'banda_elastica', 'fuerza', 'aislamiento', 1),
('Patada de tríceps con banda — Claude', 'Pisá la banda inclinada al frente y extendé el brazo hacia atrás. Apretá el tríceps al final y volvé sin perder tensión.', NULL, 'Tríceps', 'banda_elastica', 'fuerza', 'aislamiento', 1),
('Fondos en silla — Claude', 'Manos en el borde de una silla, baja el cuerpo flexionando los codos hacia atrás y empujá. Mantené la espalda cerca del asiento.', NULL, 'Tríceps', 'sin_equipamiento', 'fuerza', 'aislamiento', 2),
('Patada de tríceps con mancuerna — Claude', 'Inclinada con el brazo pegado al torso, extendé el codo llevando la mancuerna atrás. Pausa arriba apretando el tríceps y bajá controlando.', NULL, 'Tríceps', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Press francés liviano — Claude', 'Acostada, bajá la mancuerna o barra hacia la frente flexionando solo los codos. Mantené los codos quietos apuntando al techo.', NULL, 'Tríceps', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Extensión sobre la cabeza con mancuerna — Claude', 'Sentada, sostené una mancuerna con ambas manos detrás de la cabeza y estirá los brazos arriba. Codos quietos, solo se mueve el antebrazo.', NULL, 'Tríceps', 'mancuernas', 'fuerza', 'aislamiento', 2),
('Extensión sobre cabeza con kettlebell — Claude', 'Agarrá la kettlebell con ambas manos detrás de la nuca y extendé los brazos arriba. Controlá el descenso, codos apuntando adelante.', NULL, 'Tríceps', 'kettlebell', 'fuerza', 'aislamiento', 2),
('Press francés con barra — Claude', 'Acostada en banco, bajá la barra hacia la frente flexionando los codos y extendé arriba. Mantené los codos fijos, sin abrirlos.', NULL, 'Tríceps', 'barra', 'fuerza', 'aislamiento', 2),
('Extensión de tríceps en máquina — Claude', 'Sentada con los codos fijos, empujá la manija hacia abajo extendiendo los brazos. Apretá el tríceps abajo y volvé controlando.', NULL, 'Tríceps', 'maquina', 'fuerza', 'aislamiento', 2),
('Dips en paralelas — Claude', 'Sostené el cuerpo en las barras paralelas y bajá flexionando los codos hacia atrás. Mantené el torso lo más vertical posible y empujá fuerte.', NULL, 'Tríceps', 'sin_equipamiento', 'fuerza', 'empuje_horizontal', 3),
('Jalón de tríceps en polea — Claude', 'De pie frente a la polea alta, empujá la barra hacia abajo extendiendo los codos pegados al cuerpo. Controlá la subida sin abrir los codos.', NULL, 'Tríceps', 'polea', 'fuerza', 'aislamiento', 3),
('Press banca agarre cerrado con barra — Claude', 'Acostada, agarre a la altura de los hombros, bajá la barra al pecho con codos cerca del cuerpo y empujá. El foco está en el tríceps.', NULL, 'Tríceps', 'barra', 'fuerza', 'empuje_horizontal', 3),
('Extensión de tríceps con TRX — Claude', 'De pie inclinada con las cintas del TRX, flexioná los codos llevando la cabeza adelante y extendé. Mantené el cuerpo firme como tabla.', NULL, 'Tríceps', 'trx', 'fuerza', 'aislamiento', 3);
